const webhookData = $('Webhook Laravel').first().json;
const userMessage = webhookData.mensaje || webhookData.message || webhookData.pregunta || '';
const userId = webhookData.user_id || null;

const recetasCompletas = $input.first().json.recetas || [];

const dificultadMap = { 'easy': 'Fácil', 'medium': 'Media', 'hard': 'Difícil' };

const recetasFormateadas = recetasCompletas.map(r => ({
  id: r.id_receta,
  titulo: r.titulo,
  ingredientes: r.solo_ingredientes ? r.solo_ingredientes.substring(0, 200) : 'N/A',
  dificultad: dificultadMap[r.dificultad] || r.dificultad
}));

return [{
  json: {
    userMessage,
    userId,
    recetas: recetasFormateadas,
    recetasCompletas
  }
}];

let responseText = '';
const ollamaResponse = $input.first().json;

if (ollamaResponse.response) {
  responseText = ollamaResponse.response;
} else if (ollamaResponse.message?.content) {
  responseText = ollamaResponse.message.content;
}

const numMatch = responseText.replace(/\*\*/g, '').match(/\d+/);
let selectedId = numMatch ? parseInt(numMatch[0]) : 0;

const procesarData = $('Procesar Petición Laravel').first().json;
const recetasCompletas = procesarData.recetasCompletas || [];
const userMessage = procesarData.userMessage || '';

let recetaSeleccionada = null;

// Búsqueda por ID
if (selectedId > 0) {
  recetaSeleccionada = recetasCompletas.find(r => r.id_receta === selectedId) || null;
}

// Fallback: búsqueda por palabras clave
if (!recetaSeleccionada && recetasCompletas.length > 0) {
  const msgNorm = userMessage.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const palabras = msgNorm.split(/\s+/).filter(w => w.length > 3);
  let maxScore = 0;

  for (const receta of recetasCompletas) {
    const campo = (receta.titulo + ' ' + (receta.solo_ingredientes || '')).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
    let score = 0;
    for (const p of palabras) {
      if (campo.includes(p)) score += 10;
      if (receta.titulo.toLowerCase().includes(p)) score += 20;
    }
    if (score > maxScore) {
      maxScore = score;
      recetaSeleccionada = receta;
    }
  }
}

// Parsear ingredientes
const parsear = (receta) => {
  if (!receta || !receta.ingredientes_completos) return [];
  return receta.ingredientes_completos.split('|').filter(Boolean).map(ing => {
    const m = ing.match(/^(.+?)\s*\(([\d.]+)\s*(\w+)\)$/);
    if (m) return { nombre: m[1].trim(), cantidad: parseFloat(m[2]), unidad: m[3] };
    return { nombre: ing.trim(), cantidad: null, unidad: null };
  });
};

return [{
  json: {
    recetaSeleccionada,
    hasReceta: !!recetaSeleccionada,
    ingredientes: parsear(recetaSeleccionada)
  }
}];

const receta = $('Filtrar Receta por ID').first().json.recetaSeleccionada;
const ingredientes = $('Filtrar Receta por ID').first().json.ingredientes;
const aiMsg = $input.first().json.response || $input.first().json.message?.content || '';

const dificultadMap = { easy: 'Fácil', medium: 'Media', hard: 'Difícil' };
const tiempoMap = { minutes: 'minutos', hours: 'horas' };
const unidadMap = { g: 'g', kg: 'kg', mg: 'mg', l: 'l', ml: 'ml', unit: 'unidades' };

const pasos = (receta.instrucciones || '')
  .split(/\r?\n/)
  .map(step => step.replace(/^\d+[.)-]?\s*/, '').trim())
  .filter(Boolean);

return [{
  json: {
    status: 'success',
    receta: {
      id_receta: receta.id_receta,
      titulo: receta.titulo,
      descripcion: receta.descripcion,
      instrucciones: receta.instrucciones,
      pasos,
      tiempo_preparacion: receta.tiempo_preparacion,
      tiempo_preparacion_unidad: receta.tiempo_preparacion_unidad,
      tiempo_texto: receta.tiempo_preparacion + ' ' + (tiempoMap[receta.tiempo_preparacion_unidad] || receta.tiempo_preparacion_unidad),
      dificultad: receta.dificultad,
      dificultad_texto: dificultadMap[receta.dificultad] || receta.dificultad,
      porciones: receta.porciones,
      ingredientes: ingredientes.map(i => ({ nombre: i.nombre, cantidad: i.cantidad, unidad: i.unidad, unidad_texto: unidadMap[i.unidad] || i.unidad })),
      imagen_principal: receta.imagen_1,
      imagenes: [receta.imagen_1, receta.imagen_2, receta.imagen_3, receta.imagen_4, receta.imagen_5].filter(Boolean),
      autor: receta.autor_nombre,
      fecha_creacion: receta.fecha_creacion,
      mensaje_chat: aiMsg
    }
  }
}];

return [{
  json: {
    status: 'error',
    message: '🍳 No encontré una receta que coincida. Prueba con: "pasta", "burger", "fettuccine" o "spaghetti".'
  }
}];
